+        // Diagonal should be 1.0
+        assert!((corr.data().values()[0] - 1.0).abs() < 1e-10);
+        assert!((corr.data().values()[3] - 1.0).abs() < 1e-10);
+        // Off-diagonal should be 1.0 (perfect positive correlation)
+        assert!((corr.data().values()[1] - 1.0).abs() < 1e-10);
+    }
